import React, { useState, useEffect, useRef } from 'react';
import { io } from 'socket.io-client';

const StreamAnalyzer = () => {
    // Socket
    const socketRef = useRef(null);
    const [status, setStatus] = useState('Disconnected');

    // Media Refs
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const audioContextRef = useRef(null);
    const scriptProcessorRef = useRef(null);
    const audioStreamRef = useRef(null);

    // State
    const [isVideoActive, setIsVideoActive] = useState(false);
    const [isAudioActive, setIsAudioActive] = useState(false);

    // Results
    const [stressResult, setStressResult] = useState(null);
    const [lastUpdate, setLastUpdate] = useState(null);

    // Config
    const VIDEO_FPS = 5;
    const AUDIO_BUFFER_SIZE = 4096;

    useEffect(() => {
        // Connect to Socket.IO with explicit transport options
        socketRef.current = io('http://localhost:5000', {
            transports: ['websocket', 'polling'], // Try websocket first, fallback to polling
            reconnectionAttempts: 5
        });

        socketRef.current.on('connect', () => {
            setStatus('Connected');
            console.log("Socket Connected");
        });

        socketRef.current.on('connect_error', (err) => {
            console.error("Socket Connection Error:", err);
            setStatus('Error');
        });

        socketRef.current.on('disconnect', () => {
            setStatus('Disconnected');
        });

        socketRef.current.on('status', (data) => {
            console.log('Server Status:', data.msg);
        });

        socketRef.current.on('stress_update', (data) => {
            setLastUpdate(new Date());
            setStressResult(prev => ({
                ...prev,
                [data.type]: data.result
            }));
        });

        return () => {
            stopVideo();
            stopAudio();
            if (socketRef.current) socketRef.current.disconnect();
        };
    }, []);

    // ---------------------------
    // Video Handling
    // ---------------------------
    const startVideo = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
                setIsVideoActive(true);

                // Start sending frames
                const interval = setInterval(() => {
                    sendVideoFrame();
                }, 1000 / VIDEO_FPS);

                videoRef.current.frameInterval = interval;
            }
        } catch (err) {
            console.error("Error accessing webcam:", err);
            alert("Could not access webcam. Please check permissions.");
        }
    };

    const stopVideo = () => {
        if (videoRef.current && videoRef.current.srcObject) {
            const tracks = videoRef.current.srcObject.getTracks();
            tracks.forEach(track => track.stop());
            videoRef.current.srcObject = null;
            clearInterval(videoRef.current.frameInterval);
        }
        setIsVideoActive(false);
    };

    const sendVideoFrame = () => {
        if (videoRef.current && canvasRef.current && socketRef.current && socketRef.current.connected) {
            const context = canvasRef.current.getContext('2d');
            canvasRef.current.width = videoRef.current.videoWidth;
            canvasRef.current.height = videoRef.current.videoHeight;
            context.drawImage(videoRef.current, 0, 0);

            const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.7); // 0.7 quality
            socketRef.current.emit('stream_video', { image: dataUrl });
        }
    };

    // ---------------------------
    // Audio Handling
    // ---------------------------
    const startAudio = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            audioStreamRef.current = stream;
            setIsAudioActive(true);

            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
            const source = audioContextRef.current.createMediaStreamSource(stream);
            scriptProcessorRef.current = audioContextRef.current.createScriptProcessor(AUDIO_BUFFER_SIZE, 1, 1);

            scriptProcessorRef.current.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const audioData = Array.from(inputData);

                if (socketRef.current && socketRef.current.connected) {
                    socketRef.current.emit('stream_audio', {
                        audio: audioData,
                        sr: audioContextRef.current.sampleRate
                    });
                }
            };

            source.connect(scriptProcessorRef.current);
            scriptProcessorRef.current.connect(audioContextRef.current.destination);

        } catch (err) {
            console.error("Error accessing microphone:", err);
            alert("Could not access microphone. Please check permissions.");
        }
    };

    const stopAudio = () => {
        if (audioStreamRef.current) {
            audioStreamRef.current.getTracks().forEach(track => track.stop());
        }
        if (scriptProcessorRef.current) {
            scriptProcessorRef.current.disconnect();
        }
        if (audioContextRef.current) {
            audioContextRef.current.close();
        }
        setIsAudioActive(false);
    };

    // ---------------------------
    // Render
    // ---------------------------

    // Helper to get stress details from result object
    const getResultDisplay = (type) => {
        if (!stressResult || !stressResult[type]) return "Waiting for data...";

        const data = stressResult[type];
        if (data.error) return `Error: ${data.error}`;

        // Handle audio 'buffering' status
        if (data.status === 'buffering') return "Analyzing audio...";

        return `${data.predicted_class} (${data.percentage.toFixed(1)}%)`;
    };

    const getStressBadge = (type) => {
        if (!stressResult || !stressResult[type] || stressResult[type].error || stressResult[type].status === 'buffering') {
            return <span className="badge bg-secondary">Unknown</span>;
        }
        const isStress = stressResult[type].predicted_class === 'Stress';
        return (
            <span className={`badge ${isStress ? 'bg-danger' : 'bg-success'}`}>
                {stressResult[type].predicted_class}
            </span>
        );
    };

    return (
        <div className="card mt-4">
            <div className="card-header text-center">
                <h3>Real-Time Analysis</h3>
                <div className="mt-2">
                    <span className={`badge ${status === 'Connected' ? 'bg-success' : 'bg-danger'}`}>
                        Server: {status}
                    </span>
                </div>
            </div>

            <div className="card-body">
                <div className="row">
                    {/* Video Column */}
                    <div className="col-md-6 mb-4">
                        <div className="card">
                            <div className="card-header">Video Stream</div>
                            <div className="card-body text-center">
                                <div style={{
                                    border: '1px solid #dee2e6',
                                    borderRadius: '4px',
                                    background: '#000',
                                    minHeight: '240px',
                                    position: 'relative',
                                    overflow: 'hidden',
                                    marginBottom: '1rem'
                                }}>
                                    <video
                                        ref={videoRef}
                                        autoPlay
                                        playsInline
                                        muted
                                        style={{ width: '100%', height: '240px', objectFit: 'contain', display: isVideoActive ? 'block' : 'none' }}
                                    />
                                    {!isVideoActive && (
                                        <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: '#fff' }}>
                                            Camera Inactive
                                        </div>
                                    )}
                                </div>
                                <canvas ref={canvasRef} style={{ display: 'none' }} />

                                <div className="d-grid gap-2">
                                    {!isVideoActive ? (
                                        <button className="btn btn-primary" onClick={startVideo}>Start Camera</button>
                                    ) : (
                                        <button className="btn btn-outline-danger" onClick={stopVideo}>Stop Camera</button>
                                    )}
                                </div>

                                <div className="mt-3">
                                    <strong>Status: </strong> {getStressBadge('video')}
                                    <div className="small text-muted mt-1">{getResultDisplay('video')}</div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Audio Column */}
                    <div className="col-md-6 mb-4">
                        <div className="card">
                            <div className="card-header">Audio Stream</div>
                            <div className="card-body text-center">
                                <div style={{
                                    height: '100px',
                                    background: isAudioActive ? '#e8f5e9' : '#f8f9fa',
                                    borderRadius: '4px',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    marginBottom: '1rem',
                                    border: isAudioActive ? '1px solid #4caf50' : '1px solid #dee2e6'
                                }}>
                                    {isAudioActive ? (
                                        <div className="text-success fw-bold">Live Audio Active</div>
                                    ) : (
                                        <div className="text-muted">Microphone Inactive</div>
                                    )}
                                </div>

                                <div className="d-grid gap-2">
                                    {!isAudioActive ? (
                                        <button className="btn btn-primary" onClick={startAudio}>Start Microphone</button>
                                    ) : (
                                        <button className="btn btn-outline-danger" onClick={stopAudio}>Stop Microphone</button>
                                    )}
                                </div>

                                <div className="mt-3">
                                    <strong>Status: </strong> {getStressBadge('audio')}
                                    <div className="small text-muted mt-1">{getResultDisplay('audio')}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default StreamAnalyzer;
